/**
 * Split the key passages of Gerard of Cremona's "Of Astronomical Geomancy"
 * (trans. Turner, 1655; library files converted from EEBO-TCP A26563 by
 * tei-to-md.mjs) into corpus quote files under corpus/gerard/.
 *
 * This script owns the whole corpus/gerard/ directory: the two quotes that
 * predate it (attributions, casting-caution) are regenerated byte-identically
 * — verify with `git diff --stat corpus/gerard/` after running.
 *
 * Anchored extraction from a clean transcription; output reviewed by hand
 * (quality: transcribed). Re-running overwrites. Normalizations applied per
 * quote, matching the practice of the two original files: page-break
 * paragraph splits joined (`join`), a mid-sentence opening capitalized
 * (`capitalize`), a trailing ;/:/, closed as a full stop (`finalStop`).
 *
 * Topics policy: never the technique-page strings (method, intention,
 * projection-of-points, part-of-fortune, way-of-the-point, judge-witnesses,
 * springing, aspects, company, perfection, dignities) — those would inject
 * Gerard into Cattan-technique pages. `astrological-geomancy` plus safe
 * secondaries only. No figures tags: Gerard speaks of planets, not figures.
 */
import { readFileSync, writeFileSync, mkdirSync, readdirSync, statSync } from 'node:fs';
import { join as pathJoin } from 'node:path';

const chapters = new Map();
function chapterBody(file) {
  if (!chapters.has(file)) {
    const md = readFileSync(`src/content/library/gerard/${file}`, 'utf8');
    chapters.set(file, md.split('---').slice(2).join('---').trim());
  }
  return chapters.get(file);
}

