function extract(q) {
  const body = chapterBody(q.file);
  const from = body.indexOf(q.start);
  if (from === -1) throw new Error(`${q.id}: start anchor not found`);
  const endAt = body.indexOf(q.end, from);
  if (endAt === -1) throw new Error(`${q.id}: end anchor not found after start`);
  let text = body.slice(from, endAt + q.end.length).trim();
  if (q.join) text = text.replace(/\s*\n\s*\n\s*/g, ' ');
  text = text.replace(/\n{3,}/g, '\n\n');
  if (q.capitalize) text = text[0].toUpperCase() + text.slice(1);
  if (q.finalStop) text = text.replace(/[;:,]$/, '') + '.';
  if (text.length < 40) throw new Error(`${q.id}: suspiciously short extract`);
  if (text.includes('##')) throw new Error(`${q.id}: extract crosses a heading`);
  return text;
}

function frontmatter(q, text) {
  const lines = ['---', 'source: gerard', `locator: "${q.locator}"`];
  if (q.houses?.length) lines.push(`houses: [${q.houses.join(', ')}]`);
  lines.push(`topics: [${q.topics.join(', ')}]`);
  lines.push('quality: transcribed');
  if (!q.legacy) {
    const excerpt = text
      .replace(/\*/g, '')
      .replace(/\s+/g, ' ')
      .slice(0, 180)
      .replace(/\s\S*$/, '…');
    lines.push(`excerpt: ${JSON.stringify(excerpt)}`);
  }
  lines.push('---');
  return lines.join('\n');
}

const manifest = new Set();
for (const q of QUOTES) {
  const text = extract(q);
  const path = `corpus/gerard/${q.id}.md`;
  mkdirSync(path.slice(0, path.lastIndexOf('/')), { recursive: true });
  writeFileSync(path, `${frontmatter(q, text)}\n${text}\n`);
  manifest.add(path);
}

// report any file in corpus/gerard not produced by this run (never delete)
const strays = [];
(function walk(dir) {
  for (const name of readdirSync(dir)) {
    const p = pathJoin(dir, name);
    if (statSync(p).isDirectory()) walk(p);
    else if (!manifest.has(p)) strays.push(p);
  }
})('corpus/gerard');

console.log(`wrote ${manifest.size} corpus files`);
if (strays.length) console.log(`NOT mine (review): ${strays.join(', ')}`);
